class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
        escape_shell: bool = False,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority
        self.escape_shell = escape_shell

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _get_win_priority_class(self, subprocess: t.Any) -> int | None:
        return {
            "low": getattr(subprocess, "IDLE_PRIORITY_CLASS", None),
            "below_normal": getattr(subprocess, "BELOW_NORMAL_PRIORITY_CLASS", None),
            "normal": getattr(subprocess, "NORMAL_PRIORITY_CLASS", None),
            "above_normal": getattr(subprocess, "ABOVE_NORMAL_PRIORITY_CLASS", None),
            "high": getattr(subprocess, "HIGH_PRIORITY_CLASS", None),
        }.get(self.process_priority)

    def _set_unix_priority(self) -> None:
        nice_value = _EDITOR_NICE_VALUES.get(self.process_priority)  # type: ignore[arg-type]

        if nice_value is None:
            return

        try:
            os.setpriority(os.PRIO_PROCESS, 0, nice_value)
        except (AttributeError, OSError):
            pass

    def edit_file(self, filename: str) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        if self.escape_shell:
            import shlex

            editor_cmd = shlex.quote(editor)
            quoted_filename = shlex.quote(filename)
        else:
            editor_cmd = editor
            quoted_filename = f'"{filename}"'

        popen_kwargs: dict[t.Any, t.Any] = {}

        if self.process_priority is not None:
            if WIN:
                priority_class = self._get_win_priority_class(subprocess)
                if priority_class is not None:
                    popen_kwargs["creationflags"] = priority_class
            else:
                popen_kwargs["preexec_fn"] = self._set_unix_priority

        try:
            c = subprocess.Popen(
                f"{editor_cmd} {quoted_filename}",
                env=environ,
                shell=True,
                **popen_kwargs,
            )
            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e

